<?php $customer=current_customer(); ao_mfa_ensure_schema(); $profile=['enabled'=>0,'preferred_method'=>'mail','totp_secret'=>'']; try{$q=db()->prepare('SELECT * FROM auth_mfa_profiles WHERE user_type="customer" AND user_id=? LIMIT 1'); $q->execute([(int)$customer['id']]); $profile=$q->fetch() ?: $profile;}catch(Throwable $e){} $logs=[]; try{ $q=db()->prepare('SELECT * FROM auth_login_events WHERE user_type="customer" AND user_id=? ORDER BY id DESC LIMIT 50'); $q->execute([(int)$customer['id']]); $logs=$q->fetchAll() ?: []; }catch(Throwable $e){} $flash=get_flash(); ?>
<?php if($flash): ?><div class="client-alert <?= e($flash['type']) ?>"><?= e($flash['message']) ?></div><?php endif; ?>
<div class="client-card"><h3>Güvenlik ve 2FA</h3><p class="muted">Hesabınızı Mail OTP, Google Authenticator veya SMS OTP ile koruyabilirsiniz.</p><form method="post" action="<?= url('client/security/mfa-save') ?>" class="client-form"><?= csrf_field() ?><div class="security-grid"><label><strong>2FA Durumu</strong><select name="enabled"><option value="0" <?= (string)$profile['enabled']==='0'?'selected':'' ?>>Pasif</option><option value="1" <?= (string)$profile['enabled']==='1'?'selected':'' ?>>Aktif</option></select></label><label><strong>Tercih Edilen Yöntem</strong><select name="preferred_method"><option value="mail" <?= $profile['preferred_method']==='mail'?'selected':'' ?>>Mail OTP</option><option value="totp" <?= $profile['preferred_method']==='totp'?'selected':'' ?>>Google Authenticator</option><option value="sms" <?= $profile['preferred_method']==='sms'?'selected':'' ?>>SMS OTP</option></select></label><div><strong>Politika</strong><p><?= e(admin_setting('customer_mfa_policy','optional')) ?></p></div></div><button class="client-btn">Kaydet</button></form></div>
<?php if($profile['preferred_method']==='totp' || admin_setting('mfa_totp_enabled','1')==='1'): $secret=ao_mfa_get_totp_secret('customer',(int)$customer['id'], false); ?>
<div class="client-card"><h3>Google Authenticator</h3><?php if($secret): ?><p>Uygulamadaki gizli anahtarınız:</p><code class="secret-code"><?= e($secret) ?></code><?php else: ?><p class="muted">Google Authenticator seçip kaydettiğinizde gizli anahtar oluşturulur.</p><?php endif; ?></div>
<?php endif; ?>
<div class="client-card"><h3>Son Güvenlik Logları</h3><table class="client-table"><thead><tr><th>Olay</th><th>Yöntem</th><th>Durum</th><th>IP</th><th>Tarih</th></tr></thead><tbody><?php foreach($logs as $l): ?><tr><td><?= e($l['event_type']) ?></td><td><?= e($l['method']) ?></td><td><?= e($l['status']) ?></td><td><?= e($l['ip_address']) ?></td><td><?= e($l['created_at']) ?></td></tr><?php endforeach; if(!$logs): ?><tr><td colspan="5">Henüz log yok.</td></tr><?php endif; ?></tbody></table></div>
<?php /* RC12: inline style removed; visual layer is centralized. */ ?>
